# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigEntry

# Parse command-line arguments
parser = argparse.ArgumentParser()
parser.add_argument("topic_name", help="Name of the topic to create")
parser.add_argument("num_partitions", type=int, help="Number of partitions for the topic")
parser.add_argument("replication_factor", type=int, help="Replication factor for the topic")
args = parser.parse_args()

# Create Kafka client
admin_client = KafkaAdminClient(bootstrap_servers="localhost:9092")

# Create new topic
topic = NewTopic(name=args.topic_name, num_partitions=args.num_partitions, replication_factor=args.replication_factor)
admin_client.create_topics([topic])

# Configure topic settings
config_resource = ConfigResource(type="topic", name=args.topic_name)
config_entries = [ConfigEntry(name="cleanup.policy", value="delete")]
admin_client.alter_configs([config_resource], config_entries)

# Print confirmation message
print(f"Topic '{args.topic_name}' created with {args.num_partitions} partitions and {args.replication_factor} replication factor.")
print(f"Topic configuration updated with cleanup policy set to 'delete'.")